function M.combination(id)
  local p = PALETTES[id]
  assert(p, "no combination with id " .. tostring(id))
  return p
end

function M.random(size)
  local ids = (size == 2 and PALETTES_SIZE2)
           or (size == 3 and PALETTES_SIZE3)
           or (size == 4 and PALETTES_SIZE4)
  assert(ids, "size must be 2, 3, or 4")
  return PALETTES[ids[math.random(#ids)]]
end

-- Return a random single color from a swatch group (0–5)
function M.random_color(swatch)
  local group = COLORS_BY_SWATCH[swatch]
  assert(group, "swatch must be 1–6")
  return group[math.random(#group)]
end

