-- Return a random palette containing a specific color.
-- size: 2, 3, or 4 for a specific size; 0 for any size
function M.random_with_color(color_index, size)
  assert(size == 0 or size == 2 or size == 3 or size == 4, "size must be 0, 2, 3, or 4")
  local entry = COLOR_PALETTES[color_index]
  assert(entry, "color index must be 1–159")
  if size == 0 then
    local ids = {}
    for _, s in ipairs({2, 3, 4}) do
      for _, id in ipairs(entry[s]) do ids[#ids+1] = id end
    end
    if #ids == 0 then return nil end
    return PALETTES[ids[math.random(#ids)]]
  end
  local ids = entry[size]
  if #ids == 0 then return nil end
  return PALETTES[ids[math.random(#ids)]]
end

-- Find colors by name (case-insensitive substring match)
-- Returns an array of {index, color} for all matches
function M.find(query)
  local q = query:lower()
  local results = {}
  for i = 1, #COLORS do
    if COLORS[i].name:lower():find(q, 1, true) then
      results[#results+1] = {index=i, color=COLORS[i]}
    end
  end
  return results
end

return M